external_knowledge:
- 'staff with high-level access' refers to users with the role 'admin'.;
- 'items in stock' means items with a stock quantity greater than 0.;
- 'from the most recently hired to the earliest' refers to sorting by the date the user joined in descending order.

sql:
SELECT COUNT(item_id) 
FROM sizes_items 
WHERE stock_quantity <= 50;

SELECT items.item_name, (recommendations.confidence * 100) || '%' AS confidence_percentage
FROM items
JOIN recommendations ON items.item_id = recommendations.item_id;

SELECT COUNT(DISTINCT item_id) AS "Number of Items"
FROM (
  SELECT item_id FROM recommendations
  INTERSECT
  SELECT item_id FROM orders
);

SELECT items.item_name, items.item_price, sizes.size_name
FROM items
INNER JOIN sizes ON items.size_id = sizes.size_id;

SELECT COUNT(*) 
FROM orders 
WHERE user_id IN (
    SELECT DISTINCT user_id 
    FROM recommendations
);

SELECT size_name, size_description, size_order
FROM sizes
WHERE size_name IN ('XL', 'XXL', 'XXXL');
